int dp[N][N], pre[N][N];
void solve(int CASE)
{
    ll n, m, t; cin >> n >> m >> t;
    var g = vector<vector<pii>>(n + 1);
    fa(i, 1, m) {
        ll u, v, w; cin >> u >> v >> w;
        g[u].pb({ v,w });
    }
    fa(i, 0, n)fa(j, 0, n)dp[i][j] = t + 1;
    dp[1][0] = 0;
    fa(cnt, 0, n)fa(now, 1, n)if (dp[now][cnt] != t + 1) {
        for (const var& [to, w] : g[now]) {
            if (dp[to][cnt + 1] > dp[now][cnt] + w) {
                dp[to][cnt + 1] = dp[now][cnt] + w;
                pre[to][cnt + 1] = now;
            }
        }
    }
    fb(i, n, 0)if (dp[n][i] <= t) {
        var ans = vector<int>();
        int now = n, cnt = i;
        ans.pb(now);
        while (pre[now][cnt]) {
            ans.pb(pre[now][cnt]);
            now = pre[now][cnt], cnt--;
        }
        cout << ans.size() << endl;
        reverse(all(ans));
        cout << ans << endl;
        return;
    }
    return;
}
